function cleanPrompt(text) {
  return String(text || "")
    .replace(/[\n\r]/g, " ")          // remove line breaks
    .replace(/["'`]/g, "")           // remove quotes
    .replace(/[^a-zA-Z0-9\s]/g, "")  // remove special characters
    .replace(/\s+/g, " ")            // normalize spaces
    .trim();
}

const prompt = $json.output?.Image_Prompt;

return [
  {
    json: {
      Image_Prompt: cleanPrompt(prompt)
    }
  }
];

// Get incoming item
const content = $input.first().json.fullContent || "";

// Clean text (remove extra line breaks & spaces)
const cleanedContent = content
  .replace(/\n+/g, " ")   // remove line breaks
  .replace(/\s+/g, " ")   // normalize spaces
  .trim();

// Return formatted output
return [
  {
    json: {
      Full_Article: cleanedContent
    }
  }
];
